# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

class UniversalLinkHandler {
    static func handle(url: URL) -> Bool {
        guard let scheme = url.scheme, scheme == "https" else { return false }
        
        if let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
           let token = components.queryItems?.first(where: { $0.name == "token" })?.value {
            
            if let appDel = UIApplication.shared.delegate as? AppDelegate,
               let navigationController = appDel.window?.rootViewController as? UINavigationController {
                
                let resetPasswordController = ResetPasswordController(token: token)
                navigationController.pushViewController(resetPasswordController, animated: true)
                
                return true
            }
        }
        
        return false
    }
}

class AppDelegate: UIResponder, UIApplicationDelegate {
    func application(_ app: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        if let url = userActivity.webpageUrl {
            UniversalLinkHandler.handle(url: url)
        }
        
        return true
    }
}

class ResetPasswordController: UIViewController {
    let token: String
    
    init(token: String) {
        self.token = token
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
}